// ✗ Unnecessary effect
function FilteredList({ items, filter }) {
  const [filtered, setFiltered] = useState([]);

  useEffect(() => {
    setFiltered(items.filter(i => i.type === filter)); // extra render!
  }, [items, filter]);

  return <ul>{filtered.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
}

// ✓ Compute during render — no effect needed
function FilteredList({ items, filter }) {
  const filtered = items.filter(i => i.type === filter); // synchronous
  return <ul>{filtered.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
}

// ✗ Indirect: effect watches 'submitted' state
function Form() {
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    if (submitted) {
      analytics.track('form_submit');
      navigate('/thank-you');
      setSubmitted(false);
    }
  }, [submitted]); // roundabout

  return <button onClick={() => setSubmitted(true)}>Submit</button>;
}

// ✓ Direct: run logic in the event handler
function Form() {
  function handleSubmit() {
    analytics.track('form_submit');
    navigate('/thank-you');
  }

  return <button onClick={handleSubmit}>Submit</button>;
}

// ✗ Effect calls parent callback when count changes
function Counter({ onChange }) {
  const [count, setCount] = useState(0);

  useEffect(() => {
    onChange(count); // fires after render — one step removed
  }, [count, onChange]);

  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}

// ✓ Call the callback directly in the event handler
function Counter({ onChange }) {
  const [count, setCount] = useState(0);

  function handleClick() {
    const next = count + 1;
    setCount(next);
    onChange(next); // called at the same time as the state update
  }

  return <button onClick={handleClick}>{count}</button>;
}

// ✗ Effect resets selection when userId changes
function UserView({ userId }) {
  const [selected, setSelected] = useState(null);

  useEffect(() => {
    setSelected(null); // extra render every time userId changes
  }, [userId]);

  return <ItemList userId={userId} selected={selected} onSelect={setSelected} />;
}

// ✓ Use key to force remount — React resets all state automatically
function UserView({ userId }) {
  return <ItemList key={userId} userId={userId} />;
  // ItemList starts fresh with null selected whenever userId changes
}

// ✗ Unnecessary effect + state for sorted list
function SortedTable({ rows }) {
  const [sorted, setSorted] = useState([]);

  useEffect(() => {
    setSorted([...rows].sort((a, b) => a.name.localeCompare(b.name)));
  }, [rows]);

  return <table>{sorted.map(r => <tr key={r.id}><td>{r.name}</td></tr>)}</table>;
}

// ✓ Sort inline during render
function SortedTable({ rows }) {
  const sorted = [...rows].sort((a, b) => a.name.localeCompare(b.name));
  return <table>{sorted.map(r => <tr key={r.id}><td>{r.name}</td></tr>)}</table>;
}

// ✓ useMemo when the list is large and sorting is measurably expensive
function SortedTable({ rows }) {
  const sorted = useMemo(
    () => [...rows].sort((a, b) => a.name.localeCompare(b.name)),
    [rows]
  );
  return <table>{sorted.map(r => <tr key={r.id}><td>{r.name}</td></tr>)}</table>;
}

// ✗ Effect sets initial state — extra render on mount
function Search({ defaultQuery }) {
  const [query, setQuery] = useState('');

  useEffect(() => {
    setQuery(defaultQuery); // fires after mount → second render
  }, []); // eslint warning: defaultQuery not listed

  return <input value={query} onChange={e => setQuery(e.target.value)} />;
}

// ✓ useState initialiser — runs only on mount, no extra render
function Search({ defaultQuery }) {
  const [query, setQuery] = useState(defaultQuery); // correct
  return <input value={query} onChange={e => setQuery(e.target.value)} />;
}

// Note: changes to defaultQuery after mount do NOT update query.
// That is the intended behaviour — it is 'initial' value, not 'controlled'.

// ✗ Two effects: one fetches, one transforms
function UserList() {
  const [raw, setRaw] = useState([]);
  const [users, setUsers] = useState([]);

  useEffect(() => {
    fetch('/api/users').then(r => r.json()).then(setRaw);
  }, []);

  useEffect(() => {
    setUsers(raw.filter(u => u.active).map(u => ({ ...u, label: u.name })));
  }, [raw]); // extra render per fetch

  return <ul>{users.map(u => <li key={u.id}>{u.label}</li>)}</ul>;
}

// ✓ Transform inline before setState in the same effect
function UserList() {
  const [users, setUsers] = useState([]);

  useEffect(() => {
    fetch('/api/users')
      .then(r => r.json())
      .then(raw => {
        const processed = raw.filter(u => u.active).map(u => ({ ...u, label: u.name }));
        setUsers(processed); // one render, already transformed
      });
  }, []);

  return <ul>{users.map(u => <li key={u.id}>{u.label}</li>)}</ul>;
}

// ✗ Effect reads localStorage — causes extra render on mount
function Settings() {
  const [theme, setTheme] = useState('light');

  useEffect(() => {
    const saved = localStorage.getItem('theme');
    if (saved) setTheme(saved); // triggers a second render
  }, []);

  return <p>Theme: {theme}</p>;
}

// ✓ useState initialiser — reads synchronously, no extra render
function Settings() {
  const [theme, setTheme] = useState(
    () => localStorage.getItem('theme') ?? 'light'
  );

  // Write to localStorage in an effect — this IS appropriate
  useEffect(() => {
    localStorage.setItem('theme', theme);
  }, [theme]);

  return <p>Theme: {theme}</p>;
}

// ✗ Effect reads URL and sets state — extra render
function SearchPage() {
  const [query, setQuery] = useState('');

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    setQuery(params.get('q') ?? ''); // extra render on mount
  }, []);

  return <Results query={query} />;
}

// ✓ Read URL during render (with React Router v6)
import { useSearchParams } from 'react-router-dom';

function SearchPage() {
  const [searchParams] = useSearchParams();
  const query = searchParams.get('q') ?? '';
  // query is always current, no state or effect needed
  return <Results query={query} />;
}

// ✗ Effect derives a value from context
function UserBadge() {
  const { user } = useContext(AuthContext);
  const [label, setLabel] = useState('');

  useEffect(() => {
    setLabel(user ? `${user.name} (${user.role})` : 'Guest');
  }, [user]); // extra render every time user changes

  return <span>{label}</span>;
}

// ✓ Derive inline during render
function UserBadge() {
  const { user } = useContext(AuthContext);
  const label = user ? `${user.name} (${user.role})` : 'Guest';
  return <span>{label}</span>;
}

// ✗ Effect computes errors — extra render per field change
function EmailInput({ value, onChange }) {
  const [error, setError] = useState('');

  useEffect(() => {
    if (!value.includes('@')) {
      setError('Not a valid email');
    } else {
      setError('');
    }
  }, [value]); // extra render after each keystroke

  return (
    <>
      <input value={value} onChange={e => onChange(e.target.value)} />
      {error && <p>{error}</p>}
    </>
  );
}

// ✓ Derive inline — no effect, no extra render
function EmailInput({ value, onChange }) {
  const error = value && !value.includes('@') ? 'Not a valid email' : '';
  return (
    <>
      <input value={value} onChange={e => onChange(e.target.value)} />
      {error && <p>{error}</p>}
    </>
  );
}

// Before: effect computes filtered+sorted list
useEffect(() => {
  const result = items
    .filter(i => i.active)
    .sort((a, b) => a.name.localeCompare(b.name));
  setProcessed(result);
}, [items]);

// After: compute during render — fewer renders, simpler code
const processed = useMemo(
  () => items.filter(i => i.active).sort((a, b) => a.name.localeCompare(b.name)),
  [items]
);
